 57→@Composable
 58→fun FullscreenVideoScreen(onDismiss: () -> Unit) {
 59→    val context = LocalContext.current
 60→    var mediaPlayer by remember { mutableStateOf<MediaPlayer?>(null) }
 61→
 62→    Box(
 63→        modifier = Modifier
 64→            .fillMaxSize()
 65→            .background(Color.Black)
 66→            .clickable(
 67→                interactionSource = remember { MutableInteractionSource() },
 68→                indication = null
 69→            ) {
 70→                onDismiss()
 71→            }
 72→    ) {
 73→        AndroidView(
 74→            factory = { ctx ->
 75→                SurfaceView(ctx).apply {
 76→                    // 确保 SurfaceView 可见
 77→                    setZOrderOnTop(false)
 78→
 79→                    holder.addCallback(object : SurfaceHolder.Callback {
 80→                        override fun surfaceCreated(holder: SurfaceHolder) {
 81→                            try {
 82→                                val videoPath = getVideoPath(ctx)
 83→                                android.util.Log.d("FullscreenVideo", "Video path: $videoPath")
 84→
 85→                                if (videoPath.isNullOrEmpty()) {
 86→                                    android.util.Log.e("FullscreenVideo", "Video path is null or empty")
 87→                                    return
 88→                                }
 89→
 90→                                mediaPlayer = MediaPlayer().apply {
 91→                                    setOnErrorListener { mp, what, extra ->
 92→                                        android.util.Log.e("FullscreenVideo", "MediaPlayer error: what=$what, extra=$extra")
 93→                                        false
 94→                                    }
 95→
 96→                                    setOnInfoListener { mp, what, extra ->
 97→                                        android.util.Log.d("FullscreenVideo", "MediaPlayer info: what=$what, extra=$extra")
 98→                                        false
 99→                                    }
100→
101→                                    setSurface(holder.surface)
102→
103→                                    // 支持 Uri 和文件路径
104→                                    if (videoPath.startsWith("content://")) {
105→                                        setDataSource(ctx, Uri.parse(videoPath))
106→                                    } else {
107→                                        setDataSource(videoPath)
108→                                    }
109→
110→                                    isLooping = true
111→                                    setVideoScalingMode(MediaPlayer.VIDEO_SCALING_MODE_SCALE_TO_FIT_WITH_CROPPING)
112→                                    setVolume(0f, 0f) // 静音
113→
114→                                    // 异步准备
115→                                    setOnPreparedListener { mp ->
116→                                        android.util.Log.d("FullscreenVideo", "MediaPlayer prepared, starting playback")
117→                                        mp.start()
118→                                    }
119→
120→                                    android.util.Log.d("FullscreenVideo", "Starting async prepare")
121→                                    prepareAsync()
122→                                }
123→                            } catch (e: Exception) {
124→                                android.util.Log.e("FullscreenVideo", "Error initializing MediaPlayer", e)
125→                                e.printStackTrace()
126→                            }
127→                        }
128→
129→                        override fun surfaceChanged(holder: SurfaceHolder, format: Int, width: Int, height: Int) {
130→                            android.util.Log.d("FullscreenVideo", "Surface changed: ${width}x${height}")
131→                        }
132→
133→                        override fun surfaceDestroyed(holder: SurfaceHolder) {
134→                            android.util.Log.d("FullscreenVideo", "Surface destroyed")
135→                            mediaPlayer?.release()
136→                            mediaPlayer = null
137→                        }
138→                    })
139→                }
140→            },
141→            modifier = Modifier.fillMaxSize()
142→        )
143→    }
144→
145→    DisposableEffect(Unit) {
146→        onDispose {
147→            mediaPlayer?.release()
148→        }
149→    }
150→}
