152→private fun getVideoPath(context: Context): String? {
153→    return try {
154→        val file = File(context.filesDir, "video_live_wallpaper_file_path")
155→        Log.d("FullscreenVideo", "Checking video path file: ${file.absolutePath}")
156→        Log.d("FullscreenVideo", "File exists: ${file.exists()}")
157→
158→        if (file.exists()) {
159→            val path = file.readText().trim()
160→            Log.d("FullscreenVideo", "Read video path: $path")
161→
162→            // 验证路径
163→            if (path.startsWith("content://")) {
164→                Log.d("FullscreenVideo", "Path is a content URI")
165→            } else if (File(path).exists()) {
166→                Log.d("FullscreenVideo", "Path is a valid file path")
167→            } else {
168→                Log.w("FullscreenVideo", "Path does not point to a valid file")
169→            }
170→
171→            path
172→        } else {
173→            Log.e("FullscreenVideo", "Video path file does not exist!")
174→            null
175→        }
176→    } catch (e: Exception) {
177→        Log.e("FullscreenVideo", "Error reading video path", e)
178→        null
179→    }
180→}
