17→class ClearDesktopService : Service() {
18→
19→    private val unlockReceiver = object : BroadcastReceiver() {
20→        override fun onReceive(context: Context, intent: Intent) {
21→            if (intent.action == Intent.ACTION_USER_PRESENT) {
22→                // 启动全屏视频 Activity
23→                val videoIntent = Intent(context, FullscreenVideoActivity::class.java).apply {
24→                    flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_NO_HISTORY
25→                }
26→                context.startActivity(videoIntent)
27→            }
28→        }
29→    }
30→
31→    override fun onCreate() {
32→        super.onCreate()
33→
34→        // 创建通知渠道
35→        createNotificationChannel()
36→
37→        // 启动前台服务
38→        val notification = createNotification()
39→        startForeground(NOTIFICATION_ID, notification)
40→
41→        // 注册解锁广播接收器
42→        val filter = IntentFilter(Intent.ACTION_USER_PRESENT)
43→        registerReceiver(unlockReceiver, filter, RECEIVER_EXPORTED)
44→    }
45→
46→    override fun onDestroy() {
47→        super.onDestroy()
48→        try {
49→            unregisterReceiver(unlockReceiver)
50→        } catch (e: Exception) {
51→            e.printStackTrace()
52→        }
53→    }
54→
55→    override fun onBind(intent: Intent?): IBinder? = null
56→
57→    private fun createNotificationChannel() {
58→        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
59→            val channel = NotificationChannel(
60→                CHANNEL_ID,
61→                "清空桌面服务",
62→                NotificationManager.IMPORTANCE_LOW
63→            ).apply {
64→                description = "保持清空桌面功能运行"
65→            }
66→            val notificationManager = getSystemService(NotificationManager::class.java)
67→            notificationManager.createNotificationChannel(channel)
68→        }
69→    }
70→
71→    private fun createNotification(): Notification {
72→        return NotificationCompat.Builder(this, CHANNEL_ID)
73→            .setContentTitle("清空桌面已启用")
74→            .setContentText("解锁后自动显示视频壁纸")
75→            .setSmallIcon(android.R.drawable.ic_menu_view)
76→            .setPriority(NotificationCompat.PRIORITY_LOW)
77→            .build()
78→    }
79→
80→    companion object {
81→        private const val CHANNEL_ID = "clear_desktop_channel"
82→        private const val NOTIFICATION_ID = 2001
83→
84→        fun start(context: Context) {
85→            val intent = Intent(context, ClearDesktopService::class.java)
86→            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
87→                context.startForegroundService(intent)
88→            } else {
89→                context.startService(intent)
90→            }
91→        }
92→
93→        fun stop(context: Context) {
94→            val intent = Intent(context, ClearDesktopService::class.java)
95→            context.stopService(intent)
