 12→class VideoLiveWallpaperService : WallpaperService() {
 13→
 14→    internal inner class VideoEngine : Engine() {
 15→        private var mediaPlayer: MediaPlayer? = null
 16→        private var broadcastReceiver: BroadcastReceiver? = null
 17→        private var videoFilePath: String? = null
 18→
 19→        override fun onCreate(surfaceHolder: SurfaceHolder) {
 20→            super.onCreate(surfaceHolder)
 21→
 22→            videoFilePath = try {
 23→                this@VideoLiveWallpaperService.openFileInput("video_live_wallpaper_file_path")
 24→                    .bufferedReader().use { it.readText() }
 25→            } catch (e: Exception) {
 26→                null
 27→            }
 28→
 29→            val intentFilter = IntentFilter(VIDEO_PARAMS_CONTROL_ACTION)
 30→            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
 31→                ContextCompat.registerReceiver(
 32→                    this@VideoLiveWallpaperService,
 33→                    object : BroadcastReceiver() {
 34→                        override fun onReceive(context: Context, intent: Intent) {
 35→                            handleVolumeControl(intent)
 36→                        }
 37→                    }.also { broadcastReceiver = it },
 38→                    intentFilter,
 39→                    ContextCompat.RECEIVER_NOT_EXPORTED
 40→                )
 41→            } else {
 42→                registerReceiver(object : BroadcastReceiver() {
 43→                    override fun onReceive(context: Context, intent: Intent) {
 44→                        handleVolumeControl(intent)
 45→                    }
 46→                }.also { broadcastReceiver = it }, intentFilter)
 47→            }
 48→        }
 49→
 50→        private fun handleVolumeControl(intent: Intent) {
 51→            val shouldMute = intent.getBooleanExtra(KEY_ACTION, false)
 52→            mediaPlayer?.setVolume(
 53→                if (shouldMute) 0f else 1.0f,
 54→                if (shouldMute) 0f else 1.0f
 55→            )
 56→        }
 57→
 58→        override fun onSurfaceCreated(holder: SurfaceHolder) {
 59→            super.onSurfaceCreated(holder)
 60→
 61→            videoFilePath?.let { path ->
 62→                try {
 63→                    mediaPlayer = MediaPlayer().apply {
 64→                        setSurface(holder.surface)
 65→
 66→                        // 支持 Uri 和文件路径
 67→                        if (path.startsWith("content://")) {
 68→                            setDataSource(this@VideoLiveWallpaperService, Uri.parse(path))
 69→                        } else {
 70→                            setDataSource(path)
 71→                        }
 72→
 73→                        isLooping = true
 74→                        setVideoScalingMode(MediaPlayer.VIDEO_SCALING_MODE_SCALE_TO_FIT_WITH_CROPPING)
 75→
 76→                        // 异步准备
 77→                        setOnPreparedListener {
 78→                            it.start()
 79→                        }
 80→                        prepareAsync()
 81→                    }
 82→
 83→                    // 检查静音设置
 84→                    val unmuteFile = File(filesDir, "unmute")
 85→                    val volume = if (unmuteFile.exists()) 1.0f else 0f
 86→                    mediaPlayer?.setVolume(volume, volume)
 87→
 88→                } catch (e: Exception) {
 89→                    e.printStackTrace()
 90→                    mediaPlayer?.release()
 91→                    mediaPlayer = null
 92→                }
 93→            }
 94→        }
 95→
 96→        override fun onVisibilityChanged(visible: Boolean) {
 97→            mediaPlayer?.let {
 98→                if (visible && !it.isPlaying) {
 99→                    it.start()
100→                } else if (!visible && it.isPlaying) {
101→                    it.pause()
102→                }
103→            }
104→        }
105→
106→        override fun onSurfaceDestroyed(holder: SurfaceHolder) {
107→            super.onSurfaceDestroyed(holder)
108→            mediaPlayer?.let {
109→                if (it.isPlaying) it.stop()
110→                it.release()
111→            }
112→            mediaPlayer = null
113→        }
114→
115→        override fun onDestroy() {
116→            super.onDestroy()
117→            mediaPlayer?.release()
118→            mediaPlayer = null
119→            broadcastReceiver?.let { unregisterReceiver(it) }
120→        }
121→    }
122→
123→    override fun onCreateEngine(): Engine = VideoEngine()
124→
125→    companion object {
126→        const val VIDEO_PARAMS_CONTROL_ACTION = "com.wallpaper.livewallpaper"
127→        private const val KEY_ACTION = "music"
128→        private const val ACTION_MUSIC_UNMUTE = false
129→        private const val ACTION_MUSIC_MUTE = true
130→
131→        fun muteMusic(context: Context) {
132→            Intent(VIDEO_PARAMS_CONTROL_ACTION).apply {
133→                putExtra(KEY_ACTION, ACTION_MUSIC_MUTE)
134→            }.also { context.sendBroadcast(it) }
135→        }
136→
137→        fun unmuteMusic(context: Context) {
138→            Intent(VIDEO_PARAMS_CONTROL_ACTION).apply {
139→                putExtra(KEY_ACTION, ACTION_MUSIC_UNMUTE)
140→            }.also { context.sendBroadcast(it) }
141→        }
142→
143→        fun setToWallPaper(context: Context) {
144→            Intent(WallpaperManager.ACTION_CHANGE_LIVE_WALLPAPER).apply {
