18→        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
19→            return uri.toString()
20→        }
21→
22→        if (DocumentsContract.isDocumentUri(context, uri)) {
23→            when {
24→                isExternalStorageDocument(uri) -> {
25→                    val docId = DocumentsContract.getDocumentId(uri)
26→                    val split = docId.split(":")
27→                    val type = split[0]
28→                    if ("primary".equals(type, ignoreCase = true)) {
