31→                }
32→                isDownloadsDocument(uri) -> {
33→                    val id = DocumentsContract.getDocumentId(uri)
34→                    val contentUri = ContentUris.withAppendedId(
35→                        Uri.parse("content://downloads/public_downloads"),
36→                        id.toLongOrNull() ?: return null
37→                    )
38→                    return getDataColumn(context, contentUri, null, null)
39→                }
40→                isMediaDocument(uri) -> {
41→                    val docId = DocumentsContract.getDocumentId(uri)
42→                    val split = docId.split(":")
43→                    val type = split[0]
44→                    val contentUri = when (type) {
45→                        "image" -> MediaStore.Images.Media.EXTERNAL_CONTENT_URI
46→                        "video" -> MediaStore.Video.Media.EXTERNAL_CONTENT_URI
47→                        "audio" -> MediaStore.Audio.Media.EXTERNAL_CONTENT_URI
48→                        else -> null
49→                    }
50→                    val selection = "_id=?"
51→                    val selectionArgs = arrayOf(split[1])
52→                    return getDataColumn(context, contentUri, selection, selectionArgs)
53→                }
54→            }
